  switch (status) {
    case "Removed":
      return "success";
    case "To be removed":
      return "emergency";
    case "Submitted":
      return "information";
    case "In review":
      return "information";
    case "Awaiting documentation":
      return "important";
    case "Denied":
      return "emergency";
    case "Approved":
      return "success";
    case "Closed":
      return "information";
    default:
      return "information";
  }
